@import url('https://fonts.googleapis.com/css?family=Do+Hyeon');

body {
    display: flex;
    margin: 0;
    padding: 0;
    height: 100vh;
    color: #000;
    overflow: hidden;
    font-family: 'Arial', sans-serif;
}

a {
    cursor: pointer;
}

.powermode-input {
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    height: 50px;
    background: red;
    border: none;
    color: transparent;
    opacity: 0;
}

#stdout ::selection {
    background: transparent; /* WebKit/Blink Browsers */
  }
  #stdout ::-moz-selection {
    background:transparent; /* Gecko Browsers */
  }

pre {
    margin: 0;
    font-size: 12px;
    font-family: inherit;
}

#profile {
    max-width: 50%;
    overflow: hidden;
    background: #fff;
    color: #333;
    flex: 1;
    transition: all ease-in-out 0.3s;
}

#profile.hidden {
    max-width: 0%;
}

#stdout {
    position: relative;
    max-width: 100%;
    transition: all ease-in-out 0.3s;
}

body.segment-1 #stdout {
    flex: 1;

    background: #000;
    color: #fff;

    font-family: monospace;
    font-size: 14px;

    max-height: 100vh;
    overflow: auto;
    padding: 10px;
}

body.segment-1 .tty-color-white { color: #fff; }
body.segment-1 .tty-color-muted { color: #ccc; }

.tty-background-clear { background: transparent; }

/** Segment 2 */
body.segment-2 .tty-block-code {
    margin: 10px 0 !important;;
}

body.segment-3 .tty-block-code {
    padding: 15px 10px;
    background: #222;
}

body.segment-4 #stdout {
    max-width: 50%;
}

#profile {
    font-family: 'Do Hyeon', sans-serif;
    overflow: auto;
}
.welcome {
    text-align:center;
    font-size:32px;
    padding: 40px 0;
    background: #ff5722;
    color: #fff;
    font-family: 'Do Hyeon', sans-serif;
}


.wiggle {
    display: inline-block;
    animation: wiggle ease-in-out 2s infinite;
    transform-origin: bottom;
    margin: 0 20px;
    font-size:32px;
}

@keyframes wiggle {
    0% {
        transform: rotate(0deg);
    }

    33% {
        transform: rotate(-30deg);
    }

    66% {
        transform: rotate(30deg);
    }

    100% {
        transform: rotate(0deg);
    }
}

.banner {
    padding: 30px;
    background:#ff7a00;
    color:#fff;
    text-align: center;
    font-size: 24px;
}

.project .url {
    font-size:16px !important ;
}
.banner img {
    display:none;
}

.banner h2 {
    padding: 0; margin: 0;
}

.banner-1 {
    background: rgba(255, 123, 0, 0.99);
}

.banner-1, .banner-2, .banner-3, .banner-4, .banner {
    font-size: 20px;
}

.projects {
    display: flex;
    flex-wrap: wrap;
}
.project {
    min-height: 300px;
    background: rgba(255, 123, 0, 0.95);
    color: #fff;
    width:33.333333%;
    text-align: center;
}

.project .name {
    font-size: 20px;
    padding: 20px 0;
}
.project .description {
    padding: 5px 20px;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, 'Open Sans', 'Helvetica Neue', sans-serif;;
    font-size: 14px;
    margin-bottom: 20px;
    min-height: 40px;
}

.project .tags {
    display: flex;
    justify-content: center;
    flex-wrap: wrap;
    margin: 0 20px;
}

.project-list .list ul {
    text-align: left;
}

.banner-6 a {
    color: #fff;
    text-decoration: none;
}

.project a {
    color: #fff;
    text-decoration:none;
    transition: all ease-in-out 0.2s;
}
.project a:hover {
    transform: scale(1.4) rotate(5deg);
    display:block;
    text-decoration:none;
}

.project a:nth-child(2):hover {
    transform: scale(1.4) rotate(-5deg);
}

.project a:nth-child(3):hover {
    transform: scale(1.4) rotate(-2deg);
}

.project a:nth-child(4):hover {
    transform: scale(1.4) rotate(3deg);
}

.project .stats {

}
.project .stats .stat {
 width: 100%;  
 margin: 20px 0;
}
.project .stats .stat .num {
