@media (max-width: 767px) {
    body.segment-4 #stdout {
        max-width: 100%;
    }

    #profile {
        display: none;
    }

    body.segment-5 #stdout {
        transition: transform ease-in-out 0.4s;
        transform: translateX(100%);  
        width: 0 !important;
        max-width: 0% !important;
        padding: 0 !important; 
        display: none;
    }
    body.segment-5 .project {
        width: 100%;
        background: #292929 !important;
    }
    body.segment-5  #profile {
